-- Table: public.geografia

-- DROP TABLE IF EXISTS public.geografia;

CREATE TABLE IF NOT EXISTS public.global_geografia
(
    id character varying(255) COLLATE pg_catalog."default" NOT NULL,
    codigo character varying(255) COLLATE pg_catalog."default",
    codigo_ine character varying(255) COLLATE pg_catalog."default",
    codigo_iso character varying(255) COLLATE pg_catalog."default",
    concelho character varying(255) COLLATE pg_catalog."default",
    flag_alter character varying(255) COLLATE pg_catalog."default",
    flg_situacao character varying(255) COLLATE pg_catalog."default",
    freguesia character varying(255) COLLATE pg_catalog."default",
    geogr_id character varying(255) COLLATE pg_catalog."default",
    ilha character varying(255) COLLATE pg_catalog."default",
    nacionalidade character varying(255) COLLATE pg_catalog."default",
    nivel_detalhe character varying(255) COLLATE pg_catalog."default",
    nome character varying(255) COLLATE pg_catalog."default",
    nome_norm character varying(255) COLLATE pg_catalog."default",
    nome_oficial character varying(255) COLLATE pg_catalog."default",
    pais character varying(255) COLLATE pg_catalog."default",
    self_id character varying(255) COLLATE pg_catalog."default",
    short_nome character varying(255) COLLATE pg_catalog."default",
    tp_geog_cd character varying(255) COLLATE pg_catalog."default",
    zona character varying(255) COLLATE pg_catalog."default",
    CONSTRAINT geografia_pkey PRIMARY KEY (id)
)

TABLESPACE pg_default;

ALTER TABLE IF EXISTS public.geografia
    OWNER to postgres;

delete from public.global_geografia;

